INSERT INTO categories (slug, name)
VALUES
  ('backend', 'Backend'),
  ('frontend', 'Frontend'),
  ('devops', 'DevOps'),
  ('data', 'Data Science'),
  ('mobile', 'Mobile')
ON CONFLICT (slug) DO NOTHING;

INSERT INTO questions (category_id, question_text, answer_text, hint_text, source_type)
SELECT c.id,
       q.question_text,
       q.answer_text,
       q.hint_text,
       'seed'
FROM categories c
JOIN (
  VALUES
    ('backend', 'Что такое ACID в базах данных?', 'ACID — атомарность, согласованность, изолированность и долговечность транзакций.', 'Раскрой каждую букву аббревиатуры.'),
    ('backend', 'Чем REST отличается от RPC?', 'REST строится вокруг ресурсов и HTTP-семантики, RPC — вокруг вызова удаленных процедур.', 'Сравни подход к маршрутам и контракту API.'),
    ('backend', 'Что такое идемпотентность HTTP-методов?', 'Идемпотентный метод при повторном вызове приводит систему к тому же состоянию.', 'Вспомни PUT и DELETE.'),
    ('backend', 'Зачем нужен индекс в SQL?', 'Индекс ускоряет поиск и сортировку по колонкам, но увеличивает стоимость записи.', 'Подумай о trade-off между SELECT и INSERT/UPDATE.'),
    ('backend', 'Что такое N+1 проблема?', 'Это множественные лишние запросы к БД при загрузке связанных данных по одному.', 'Часто решается eager loading/join.'),
    ('backend', 'Чем отличается аутентификация от авторизации?', 'Аутентификация проверяет кто пользователь, авторизация — что ему разрешено.', 'Кто ты и что тебе можно.'),
    ('backend', 'Что такое кэширование на уровне API?', 'Это сохранение результатов запросов для ускорения повторных обращений.', 'Вспомни TTL и инвалидацию.'),
    ('backend', 'Зачем нужен message broker?', 'Брокер сообщений позволяет асинхронно обмениваться событиями между сервисами.', 'Примеры: RabbitMQ, Kafka.'),
    ('backend', 'Что такое rate limiting?', 'Ограничение числа запросов за период для защиты API от перегрузки и abuse.', 'Вспомни token bucket/sliding window.'),
    ('backend', 'Как работает pagination и зачем она нужна?', 'Pagination разбивает выдачу на страницы, чтобы уменьшить нагрузку и объем ответа.', 'Сравни offset/limit и cursor pagination.'),

    ('frontend', 'Что такое Virtual DOM?', 'Это промежуточное представление DOM, позволяющее применять изменения в реальный DOM эффективнее.', 'Подумай о diff и batch update.'),
    ('frontend', 'Для чего нужен debounce?', 'Debounce откладывает вызов функции до паузы в потоке событий.', 'Типичный кейс — поиск по мере ввода.'),
    ('frontend', 'Чем отличается throttle от debounce?', 'Throttle ограничивает частоту вызовов по интервалу, debounce ждет паузу перед вызовом.', 'Один про регулярность, второй про паузу.'),
    ('frontend', 'Что такое event loop в браузере?', 'Event loop обрабатывает очередь задач и микрозадач, обеспечивая неблокирующее выполнение JS.', 'Вспомни call stack, task queue, microtask queue.'),
    ('frontend', 'Почему важна мемоизация в React?', 'Мемоизация снижает лишние рендеры и перерасчеты при неизменных входных данных.', 'React.memo, useMemo, useCallback.'),
    ('frontend', 'Что такое hydration в SSR?', 'Hydration — привязка клиентского JS к серверно-отрендеренной разметке.', 'SSR HTML становится интерактивным.'),
    ('frontend', 'Для чего нужен CORS?', 'CORS контролирует доступ к ресурсам между разными источниками (origin).', 'Проверь роль заголовка Access-Control-Allow-Origin.'),
    ('frontend', 'Что такое accessibility (a11y)?', 'Это практика создания интерфейсов, доступных людям с ограничениями и разными способами ввода.', 'Семантика, aria-атрибуты, контраст, фокус.'),
    ('frontend', 'Когда использовать state management библиотеку?', 'Когда локального state недостаточно и нужно централизованно управлять состоянием приложения.', 'Оцени сложность shared state и side effects.'),
    ('frontend', 'Что такое code splitting?', 'Разделение бандла на части, загружаемые по требованию для ускорения первого рендера.', 'Динамический import и lazy loading.'),

    ('devops', 'Что такое CI/CD?', 'CI/CD — практики непрерывной интеграции и доставки/развертывания.', 'Раздели процесс на CI и CD части.'),
    ('devops', 'Зачем нужен Docker?', 'Docker упаковывает приложение и зависимости в контейнер для воспроизводимого запуска.', 'Одинаковая среда dev/stage/prod.'),
    ('devops', 'Что такое Kubernetes?', 'Kubernetes оркестрирует контейнеры: деплой, масштабирование, self-healing.', 'Pod, Deployment, Service — ключевые сущности.'),
    ('devops', 'Что такое Infrastructure as Code?', 'IaC — управление инфраструктурой через код и версионирование конфигураций.', 'Примеры: Terraform, Ansible.'),
    ('devops', 'Для чего нужен health check?', 'Проверка жизнеспособности сервиса для перезапуска и исключения из балансировки.', 'Readiness vs Liveness probes.'),
    ('devops', 'Что такое blue-green deployment?', 'Стратегия релиза с двумя средами, где переключение трафика выполняется на новую версию.', 'Минимизирует downtime и откат проще.'),
    ('devops', 'Чем отличается horizontal и vertical scaling?', 'Horizontal — добавление инстансов, vertical — увеличение ресурсов одного узла.', 'Scale out vs scale up.'),
    ('devops', 'Что такое observability?', 'Набор практик для понимания состояния системы через логи, метрики и трассировки.', 'Logs + Metrics + Traces.'),
    ('devops', 'Зачем нужен reverse proxy?', 'Reverse proxy принимает входящий трафик и маршрутизирует его к внутренним сервисам.', 'Nginx часто используется для SSL и балансировки.'),
    ('devops', 'Что такое секреты в DevOps и как их хранить?', 'Секреты — чувствительные данные, их хранят в vault/secret manager, а не в репозитории.', 'Никогда не хранить ключи в открытом .env в git.'),

    ('data', 'Что такое переобучение модели?', 'Переобучение — когда модель хорошо работает на train и плохо обобщает на новых данных.', 'Сравни train и validation метрики.'),
    ('data', 'Что такое недообучение?', 'Недообучение — модель слишком простая и плохо работает и на train, и на validation.', 'Высокий bias.'),
    ('data', 'Для чего нужен train/validation/test split?', 'Разделение данных нужно для обучения, подбора гиперпараметров и честной итоговой оценки.', 'Тестовую выборку не используют при тюнинге.'),
    ('data', 'Что такое precision и recall?', 'Precision — доля верных позитивных предсказаний, recall — доля найденных позитивов.', 'Подумай о false positive и false negative.'),
    ('data', 'Что показывает ROC-AUC?', 'ROC-AUC оценивает способность модели различать классы при разных порогах.', 'Площадь под ROC-кривой от 0.5 до 1.0.'),
    ('data', 'Что такое feature engineering?', 'Создание и преобразование признаков для улучшения качества модели.', 'Категориальные кодировки, агрегации, нормализация.'),
    ('data', 'Зачем нужна нормализация признаков?', 'Нормализация приводит признаки к сопоставимому масштабу для стабильного обучения.', 'Важно для градиентных методов и расстояний.'),
    ('data', 'Что такое leakage в ML?', 'Leakage — утечка информации из будущего/таргета в признаки, завышающая метрики.', 'Проверь, не использует ли признак target напрямую.'),
    ('data', 'Когда использовать кросс-валидацию?', 'Кросс-валидация нужна для более устойчивой оценки модели на малых/средних датасетах.', 'K-fold снижает зависимость от одного разбиения.'),
    ('data', 'Что такое baseline модель?', 'Baseline — простая отправная модель для сравнения улучшений.', 'Без baseline сложно доказать прогресс.'),

    ('mobile', 'Зачем нужен слой ViewModel?', 'ViewModel отделяет UI-логику от представления и переживает изменения конфигурации.', 'Вспомни MVVM и управление состоянием.'),
    ('mobile', 'Что такое жизненный цикл Activity/Fragment?', 'Это последовательность состояний экрана, определяющая когда инициализировать и освобождать ресурсы.', 'onCreate/onStart/onResume/onPause/onStop/onDestroy.'),
    ('mobile', 'Чем отличается local storage от secure storage?', 'Secure storage шифрует чувствительные данные, local storage хранит без усиленной защиты.', 'Токены лучше хранить в защищенном хранилище.'),
    ('mobile', 'Что такое deep link?', 'Deep link открывает конкретный экран приложения по URL.', 'Есть custom scheme и app/universal links.'),
    ('mobile', 'Зачем нужен offline-first подход?', 'Приложение продолжает работать без сети и синхронизирует данные при восстановлении соединения.', 'Кэш + очередь операций.'),
    ('mobile', 'Что такое dependency injection в мобильной разработке?', 'DI управляет созданием зависимостей и упрощает тестирование и поддержку кода.', 'Hilt/Koin или ручной composition root.'),
    ('mobile', 'Как уменьшить расход батареи приложением?', 'Сокращать фоновую активность, оптимизировать сетевые запросы и использовать системные планировщики.', 'WorkManager/BackgroundTasks вместо постоянных сервисов.'),
    ('mobile', 'Что такое ANR на Android?', 'ANR — Application Not Responding, когда главный поток блокируется слишком долго.', 'Не выполнять тяжелую работу в UI thread.'),
    ('mobile', 'Зачем нужна пагинация в мобильных списках?', 'Пагинация снижает потребление памяти и трафика, загружая данные порциями.', 'Lazy loading при скролле.'),
    ('mobile', 'Что такое crash-free rate?', 'Метрика доли сессий без падений, показывающая стабильность приложения.', 'Важна для оценки качества релизов.')
) AS q(slug, question_text, answer_text, hint_text)
ON c.slug = q.slug
WHERE NOT EXISTS (
  SELECT 1
  FROM questions existing
  WHERE existing.category_id = c.id
    AND existing.question_text = q.question_text
);
